// ============================================================
// ANIMATED COMPONENTS
// ============================================================
function AnimatedCounter({ end, suffix = "", duration = 2000 }) {
  const [count, setCount] = useState(0);
  const ref = useRef(null);
  const started = useRef(false);

  useEffect(() => {
    const observer = new IntersectionObserver(([entry]) => {
      if (entry.isIntersecting && !started.current) {
        started.current = true;
        let start = 0;
        const step = end / (duration / 16);
        const timer = setInterval(() => {
          start += step;
          if (start >= end) { setCount(end); clearInterval(timer); }
          else setCount(Math.floor(start));
        }, 16);
      }
    });
    if (ref.current) observer.observe(ref.current);
    return () => observer.disconnect();
  }, [end, duration]);

  return <span ref={ref}>{count}{suffix}</span>;
}

function CandlestickChart() {
  const candles = [
    { o: 60, h: 80, l: 50, c: 75, up: true },
    { o: 75, h: 85, l: 65, c: 70, up: false },
    { o: 70, h: 90, l: 68, c: 88, up: true },
    { o: 88, h: 95, l: 80, c: 82, up: false },
    { o: 82, h: 100, l: 78, c: 98, up: true },
    { o: 98, h: 105, l: 88, c: 92, up: false },
    { o: 92, h: 110, l: 90, c: 108, up: true },
  ];
  return (
    <div style={{ display: "flex", alignItems: "flex-end", gap: "8px", height: "120px", padding: "10px" }}>
      {candles.map((c, i) => {
        const maxH = 110, minH = 50, range = maxH - minH;
        const bodyTop = Math.max(c.o, c.c);
        const bodyBot = Math.min(c.o, c.c);
        const bodyH = ((bodyTop - bodyBot) / range) * 80 + 8;
        const wickH = ((c.h - c.l) / range) * 80;
        const color = c.up ? "#00E676" : "#FF3D00";
        return (
          <div key={i} style={{ display: "flex", flexDirection: "column", alignItems: "center", flex: 1, animation: `candleFloat ${1 + i * 0.2}s ease-in-out infinite alternate` }}>
            <div style={{ width: 2, height: `${wickH * 0.3}px`, background: color, opacity: 0.7 }} />
            <div style={{ width: "100%", height: `${bodyH}px`, background: c.up ? `linear-gradient(180deg, ${color}88, ${color})` : color, borderRadius: 2, border: `1px solid ${color}`, boxShadow: `0 0 8px ${color}66` }} />
            <div style={{ width: 2, height: `${wickH * 0.2}px`, background: color, opacity: 0.7 }} />
          </div>
        );
      })}
    </div>
  );
}

function FloatingParticles() {
  const particles = Array.from({ length: 30 }, (_, i) => ({
    id: i,
    x: Math.random() * 100,
    y: Math.random() * 100,
    size: Math.random() * 4 + 1,
    dur: Math.random() * 6 + 4,
    delay: Math.random() * 4,
    color: i % 3 === 0 ? "#FFD700" : i % 3 === 1 ? "#003C8F" : "#00E676",
  }));
  return (
    <div style={{ position: "absolute", inset: 0, overflow: "hidden", pointerEvents: "none" }}>
      {particles.map(p => (
        <div key={p.id} style={{
          position: "absolute", left: `${p.x}%`, top: `${p.y}%`,
          width: p.size, height: p.size, borderRadius: "50%",
          background: p.color, opacity: 0.6,
          animation: `particleFloat ${p.dur}s ${p.delay}s ease-in-out infinite alternate`,
          boxShadow: `0 0 ${p.size * 2}px ${p.color}`,
        }} />
      ))}
    </div>
  );
}

