// ============================================================
// AI CHATBOT
// ============================================================
function AIChatbot({ onClose }) {
  const [messages, setMessages] = useState([
    { role: "assistant", text: "🙏 Namaste! I'm BITMillion AI Assistant. How can I help you today?\n\n• Course Information\n• Maharaja Strategy\n• Enrollment Help\n• General Questions" }
  ]);
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const messagesEnd = useRef(null);

  useEffect(() => { messagesEnd.current?.scrollIntoView({ behavior: "smooth" }); }, [messages]);

  const send = async () => {
    if (!input.trim()) return;
    const userMsg = input.trim();
    setInput("");
    setMessages(prev => [...prev, { role: "user", text: userMsg }]);
    setLoading(true);

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: `You are BITMillion AI Assistant for BITMillion Trading, India's advanced trading education platform. 
Founder: Dr. Rahul Saini. Founded: 26 January 2022. 600+ students trained.
Main courses: Zero To Advance Indian Stock Market Course (₹3999), Maharaja Strategy (₹1599).
Contact: +91 7425932778, Bitmilliontrading@gmail.com
Telegram: https://t.me/officialbitmilliontrading
Answer in a helpful, friendly manner. Use Hindi mixed with English (Hinglish) occasionally. Keep responses concise.`,
          messages: [
            ...messages.filter(m => m.role !== "assistant" || messages.indexOf(m) > 0).map(m => ({ role: m.role, content: m.text })),
            { role: "user", content: userMsg }
          ]
        })
      });
      const data = await res.json();
      const reply = data.content?.map(b => b.text || "").join("") || "Sorry, I couldn't process that. Please contact us on WhatsApp: +91 7425932778";
      setMessages(prev => [...prev, { role: "assistant", text: reply }]);
    } catch {
      setMessages(prev => [...prev, { role: "assistant", text: "Network error. Please contact us directly: +91 7425932778" }]);
    }
    setLoading(false);
  };

  return (
    <div style={{ position: "fixed", bottom: 90, right: 20, width: 340, height: 480, background: "rgba(0,15,35,0.97)", border: "1px solid rgba(255,215,0,0.3)", borderRadius: 20, display: "flex", flexDirection: "column", overflow: "hidden", zIndex: 2000, boxShadow: "0 20px 60px rgba(0,0,0,0.7), 0 0 30px rgba(255,215,0,0.1)" }}>
      <div style={{ background: "linear-gradient(135deg, #001B44, #003C8F)", padding: "14px 16px", display: "flex", justifyContent: "space-between", alignItems: "center", borderBottom: "1px solid rgba(255,215,0,0.2)" }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{ width: 36, height: 36, borderRadius: "50%", background: "linear-gradient(135deg, #FFD700, #F8B400)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "1.1rem" }}>🤖</div>
          <div>
            <div style={{ color: "#FFD700", fontWeight: 800, fontSize: "0.9rem" }}>BITMillion AI</div>
            <div style={{ color: "#00E676", fontSize: "0.7rem" }}>● Online</div>
          </div>
        </div>
        <button onClick={onClose} style={{ background: "none", border: "none", color: "#88aadd", cursor: "pointer", fontSize: "1.2rem" }}>✕</button>
      </div>

      <div style={{ flex: 1, overflowY: "auto", padding: "14px", display: "flex", flexDirection: "column", gap: 10 }}>
        {messages.map((msg, i) => (
          <div key={i} style={{ display: "flex", justifyContent: msg.role === "user" ? "flex-end" : "flex-start" }}>
            <div style={{ maxWidth: "85%", background: msg.role === "user" ? "linear-gradient(135deg, #003C8F, #0055aa)" : "rgba(255,215,0,0.08)", border: msg.role === "user" ? "none" : "1px solid rgba(255,215,0,0.2)", borderRadius: 12, padding: "10px 14px", color: "#fff", fontSize: "0.85rem", lineHeight: 1.5, whiteSpace: "pre-wrap" }}>
              {msg.text}
            </div>
          </div>
        ))}
        {loading && (
          <div style={{ display: "flex", gap: 4, padding: "10px 14px" }}>
            {[0, 1, 2].map(i => <div key={i} style={{ width: 8, height: 8, borderRadius: "50%", background: "#FFD700", animation: `dotPulse 1s ${i * 0.2}s ease-in-out infinite` }} />)}
          </div>
        )}
        <div ref={messagesEnd} />
      </div>

      <div style={{ padding: "12px", borderTop: "1px solid rgba(255,215,0,0.1)", display: "flex", gap: 8 }}>
        <input value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === "Enter" && send()}
          placeholder="Ask anything..." style={{ flex: 1, background: "rgba(0,0,0,0.4)", border: "1px solid rgba(255,215,0,0.2)", borderRadius: 10, padding: "10px 14px", color: "#fff", fontSize: "0.85rem", outline: "none" }} />
        <button onClick={send} disabled={loading}
          style={{ background: "linear-gradient(135deg, #FFD700, #F8B400)", border: "none", borderRadius: 10, width: 40, cursor: "pointer", fontSize: "1rem", display: "flex", alignItems: "center", justifyContent: "center" }}>
          →
        </button>
      </div>
    </div>
  );
}

