// ============================================================
// MAIN APP
// ============================================================
export default function App() {
  const [showLogin, setShowLogin] = useState(false);
  const [user, setUser] = useState(null);
  const [showChat, setShowChat] = useState(false);
  const [showDashboard, setShowDashboard] = useState(false);

  useEffect(() => {
    try {
      const saved = localStorage.getItem("bitmillion_user");
      if (saved) setUser(JSON.parse(saved));
    } catch {}
  }, []);

  const handleLogin = (u) => {
    setUser(u);
    setShowDashboard(true);
  };

  const handleLogout = () => {
    setUser(null);
    setShowDashboard(false);
    localStorage.removeItem("bitmillion_user");
  };

  if (showDashboard && user) {
    return (
      <>
        <style>{CSS}</style>
        <Navbar setPage={() => setShowDashboard(false)} activeSection="" setShowLogin={setShowLogin} />
        <StudentDashboard user={user} onLogout={handleLogout} />
      </>
    );
  }

  return (
    <>
      <style>{CSS}</style>
      <Navbar setPage={() => {}} activeSection="home" setShowLogin={setShowLogin} />

      <main>
        <HeroSection />
        <AboutSection />
        <CoursesSection />
        <MaharajaSection />
        <LiveClassesSection />
        <ResultsSection />
        <TradingToolsSection />
        <MarketUpdateSection />
        <MembershipSection />
        <BlogSection />
        <SocialSection />
        <ContactSection />
      </main>

      <Footer />

      {/* Floating Buttons */}
      <div style={{ position: "fixed", bottom: 20, right: 20, display: "flex", flexDirection: "column", gap: 12, zIndex: 1500 }}>
        <a href="https://wa.me/917425932778" target="_blank" rel="noopener noreferrer"
          style={{ width: 52, height: 52, borderRadius: "50%", background: "linear-gradient(135deg, #25D366, #1da851)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "1.4rem", boxShadow: "0 4px 20px rgba(37,211,102,0.4)", textDecoration: "none", animation: "floatBtn 2s ease-in-out infinite alternate" }}>
          💬
        </a>
        <button onClick={() => setShowChat(!showChat)}
          style={{ width: 52, height: 52, borderRadius: "50%", background: "linear-gradient(135deg, #FFD700, #F8B400)", border: "none", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "1.4rem", boxShadow: "0 4px 20px rgba(255,215,0,0.4)", cursor: "pointer" }}>
          🤖
        </button>
        {user && (
          <button onClick={() => setShowDashboard(true)}
            style={{ width: 52, height: 52, borderRadius: "50%", background: "linear-gradient(135deg, #003C8F, #0055bb)", border: "none", display: "flex", alignItems: "center", justifyContent: "center", fontSize: "1.2rem", boxShadow: "0 4px 20px rgba(0,60,143,0.4)", cursor: "pointer" }}>
            🎓
          </button>
        )}
      </div>

      {showChat && <AIChatbot onClose={() => setShowChat(false)} />}
      {showLogin && <StudentLoginModal onClose={() => setShowLogin(false)} onLogin={handleLogin} />}
    </>
  );
}

// ============================================================
// GLOBAL CSS
// ============================================================
const CSS = `
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #000d1f; color: #fff; overflow-x: hidden; }
  ::-webkit-scrollbar { width: 6px; }
  ::-webkit-scrollbar-track { background: #000d1f; }
  ::-webkit-scrollbar-thumb { background: linear-gradient(#FFD700, #003C8F); border-radius: 3px; }

  @keyframes logoFloat {
    from { transform: translateY(0) rotate(-1deg); filter: drop-shadow(0 0 15px rgba(255,215,0,0.4)); }
    to { transform: translateY(-8px) rotate(1deg); filter: drop-shadow(0 0 25px rgba(255,215,0,0.7)); }
  }
  @keyframes symbolFloat {
    from { transform: translateY(0) rotate(-3deg); opacity: 0.3; }
    to { transform: translateY(-20px) rotate(3deg); opacity: 0.7; }
  }
  @keyframes particleFloat {
    from { transform: translateY(0) scale(1); }
    to { transform: translateY(-30px) scale(1.5); }
  }
  @keyframes candleFloat {
    from { transform: scaleY(1); }
    to { transform: scaleY(1.1); }
  }
  @keyframes tickerScroll {
    from { transform: translateX(0); }
    to { transform: translateX(-50%); }
  }
  @keyframes pulse {
    0%, 100% { box-shadow: 0 0 10px rgba(255,215,0,0.3); }
    50% { box-shadow: 0 0 30px rgba(255,215,0,0.6); }
  }
  @keyframes floatBtn {
    from { transform: translateY(0); }
    to { transform: translateY(-5px); }
  }
  @keyframes dotPulse {
    0%, 100% { transform: scale(0.6); opacity: 0.4; }
    50% { transform: scale(1); opacity: 1; }
  }

  .desktop-nav { display: flex; }
  .mobile-menu-btn { display: none !important; }

  @media (max-width: 900px) {
    .desktop-nav { display: none !important; }
    .mobile-menu-btn { display: flex !important; }
  }

  @media (max-width: 600px) {
    .timeline-line { display: none; }
  }

  input::placeholder { color: #445566; }
  textarea::placeholder { color: #445566; }
  a { transition: opacity 0.2s; }
  a:hover { opacity: 0.85; }
  button { font-family: inherit; }
`;
